import { pushable } from 'it-pushable';
// messagePushable is a shortcut to build a pushable for messages.
export function messagePushable() {
    return pushable({ objectMode: true });
}
// writeToPushable writes the incoming server data to the pushable.
//
// this will not throw an error: it instead ends out w/ the error.
export async function writeToPushable(dataSource, out) {
    try {
        for await (const data of dataSource) {
            out.push(data);
        }
        out.end();
    }
    catch (err) {
        out.end(err);
    }
}
export function buildPushableSink(target) {
    return async (source) => {
        try {
            if (Symbol.asyncIterator in source) {
                for await (const pkt of source) {
                    target.push(pkt);
                }
            }
            else {
                for (const pkt of source) {
                    target.push(pkt);
                }
            }
            target.end();
        }
        catch (err) {
            target.end(err);
        }
    };
}
